interface CommandEntry {
  label: string;
  command: string;
}

interface PlatformData {
  id: string;
  name: string;
  icon: React.FC;
  tool: string;
  entries: CommandEntry[];
  docsUrl: string;
}

const LTS = "25";

const platforms: PlatformData[] = [
  {
    id: "mac",
    name: "macOS",
    icon: AppleIcon,
    tool: "Homebrew",
    entries: [
      { label: "Latest LTS", command: `brew install --cask temurin@${LTS}` },
      { label: "Java 8", command: `brew install --cask temurin@8` },
    ],
    docsUrl: "https://docs.brew.sh/Manpage",
  },
  {
    id: "win",
    name: "Windows",
    icon: WindowsIcon,
    tool: "Winget",
    entries: [
      {
        label: "Latest LTS",
        command: `winget install EclipseAdoptium.Temurin.${LTS}.JDK`,
      },
      {
        label: "Java 11",
        command: `winget install EclipseAdoptium.Temurin.11.JDK`,
      },
    ],
    docsUrl: "https://docs.microsoft.com/en-us/windows/package-manager/winget/",
  },
  {
    id: "linux",
    name: "Linux",
    icon: LinuxIcon,
    tool: "Package manager",
    entries: [
      {
        label: "Debian / Ubuntu",
        command: `apt-get install temurin-${LTS}-jdk`,
      },
      { label: "CentOS / RHEL", command: `yum install temurin-${LTS}-jdk` },
      { label: "openSUSE", command: `zypper install temurin-${LTS}-jdk` },
    ],
    docsUrl: "/installation/linux",
  },
];

function getDefaultTab(userOS: UserOS): number {
  if (userOS === UserOS.MAC) return 0;
  if (userOS === UserOS.LINUX || userOS === UserOS.UNIX) return 2;
  return 1;
}

const InstallTabs = (): React.ReactNode => {
  const userOS = detectOS();
  const [active, setActive] = useState(() => getDefaultTab(userOS));
  const [copied, setCopied] = useState<string | null>(null);

  const current = platforms[active];

  const handleCopy = (cmd: string) => {
    navigator.clipboard.writeText(cmd);
    setCopied(cmd);
    setTimeout(() => setCopied(null), 1500);
  };

  return (
    <div className="install-card my-8 max-w-xl">
      {/* Platform selector */}
      <div className="install-tabs flex gap-1 mb-4">
        {platforms.map((p, i) => (
          <button
            key={p.id}
            onClick={() => setActive(i)}
            className={`install-tab flex items-center gap-1.5 py-2 px-3 text-sm font-semibold rounded-lg transition-colors ${
              i === active
                ? "install-tab--active bg-white/10 text-white"
                : "text-white/40 hover:text-white/70"
            }`}
          >
            <p.icon />
            {p.name}
          </button>
        ))}
      </div>

      {/* Content */}
      <div>
        <p className="install-tool-label text-xs uppercase tracking-wider text-white/40 font-semibold mb-2">
          Install via {current.tool}
        </p>

        <div className="space-y-3">
          {current.entries.map((entry) => (
            <div key={entry.label} className="install-row group">
              <span className="install-row-label text-[11px] font-medium text-white/40 block mb-1">
                {entry.label}
              </span>
              <div className="install-code-block flex items-center justify-between rounded-lg bg-white/[0.06] border border-white/[0.08] px-4 py-2.5">
                <code className="install-row-cmd text-[13px] text-white/90 font-mono">
                  {entry.command}
                </code>
                <button
                  onClick={() => handleCopy(entry.command)}
                  className="install-copy shrink-0 text-[11px] font-semibold text-white/30 hover:text-white/70 transition-colors opacity-0 group-hover:opacity-100 ml-3"
                  aria-label={`Copy: ${entry.command}`}
                >
                  {copied === entry.command ? "Copied!" : "Copy"}
                </button>
              </div>
            </div>
          ))}
        </div>

        <a
          href={current.docsUrl}
          className="inline-block mt-4 text-sm font-medium text-pink hover:underline"
        >
          Read documentation →
        </a>
      </div>
    </div>
  );
};

export default InstallTabs;
